import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchRecords();
  }, []);

  const fetchRecords = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch records');
      }
      const data = await response.json();
      setIndicatorsData(data);
    } catch (error) {
      console.error('Error fetching records:', error);
      setError('Failed to load records');
    }
  };

  const handleInputChange = async (e, recordId, field) => {
    const { value } = e.target;
    const user_id = localStorage.getItem('user_id');

    if (!user_id || !recordId) {
      return;
    }

    setIndicatorsData(prevData => 
      prevData.map(record => 
        record.id === recordId 
          ? { ...record, [field]: value }
          : record
      )
    );

    try {
      const updateResponse = await fetch(`http://localhost:5000/api/update-health-record/${recordId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          [field]: value
        }),
      });

      if (!updateResponse.ok) {
        throw new Error('Failed to update record');
      }

      setSuccess('Record updated successfully');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      console.error('Error updating record:', err);
      setError('Failed to update record');
      setTimeout(() => setError(''), 2000);
      await fetchRecords();
    }
  };

  const handleAddNewRow = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const emptyRecord = {
      date: new Date().toISOString().split('T')[0],
      FEV1: '',
      FVC: '',
      PEF: '',
      respiratory_rate: '',
      pulse: '',
      cough: '',
      breathlessness: '',
      wheezing: '',
      chest_tightness: '',
      nighttime_awakenings: '',
      medicine: '',
      user_id: parseInt(user_id)
    };

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(emptyRecord),
      });

      if (!response.ok) {
        throw new Error('Failed to create record');
      }

      await fetchRecords();
      setSuccess('New record added');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError(err.message);
      setTimeout(() => setError(''), 2000);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row) => (
                <tr key={row.id}>
                  <td>
                    <input
                      type="date"
                      value={row.date ? row.date.split('T')[0] : ''}
                      onChange={(e) => handleInputChange(e, row.id, 'date')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FEV1 || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'FEV1')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FVC || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'FVC')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.PEF || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'PEF')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.respiratory_rate || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'respiratory_rate')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.pulse || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'pulse')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="3"
                      value={row.cough || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'cough')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.breathlessness || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'breathlessness')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.wheezing || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'wheezing')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.chest_tightness || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'chest_tightness')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      value={row.nighttime_awakenings || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'nighttime_awakenings')}
                    />
                  </td>
                  <td>
                    <input
                      type="text"
                      value={row.medicine || ''}
                      onChange={(e) => handleInputChange(e, row.id, 'medicine')}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <button onClick={handleAddNewRow} className="add-row-button">
          Add New Row
        </button>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
